import { Navegador } from './navigations/MainNavigator';

export default function App() {
  return <Navegador />;
}

import { initializeApp } from 'firebase/app';
import { getAuth } from 'firebase/auth';
import { getDatabase } from 'firebase/database';

const firebaseConfig = {
  apiKey: 'TU_API_KEY',
  authDomain: 'TU_AUTH_DOMAIN',
  projectId: 'TU_PROJECT_ID',
  storageBucket: 'TU_BUCKET',
  messagingSenderId: 'TU_ID',
  appId: 'TU_APP_ID'
};

const app = initializeApp(firebaseConfig);
export const auth = getAuth(app);
export const db = getDatabase(app);

import { createStackNavigator } from '@react-navigation/stack';
import LoginScreen from '../screens/LoginScreen';
import RegistroScreen from '../screens/RegistroScreen';
import { createDrawerNavigator } from '@react-navigation/drawer';
import GuardarScreen from '../screens/GuardarScreen';
import ListaScreen from '../screens/ListaScreen';
import NotasScreen from '../screens/NotasScreen';
import { NavigationContainer } from '@react-navigation/native';
import InformacionScreen from '../screens/InformacionScreen';

const Stack = createStackNavigator();
const Drawer = createDrawerNavigator();

function MyStack() {
  return (
    <Stack.Navigator initialRouteName='Login'>
      <Stack.Screen name='Login' component={LoginScreen} />
      <Stack.Screen name='Registro' component={RegistroScreen} />
      <Stack.Screen name='Drawer' component={MyDrawer} />
    </Stack.Navigator>
  );
}

function MyDrawer() {
  return (
    <Drawer.Navigator initialRouteName='Guardar'>
      <Drawer.Screen name='Guardar' component={GuardarScreen} />
      <Drawer.Screen name='Peliculas' component={ListaScreen} />
      <Drawer.Screen name='Notas' component={NotasScreen} />
      <Drawer.Screen name='Informacion' component={InformacionScreen} />
    </Drawer.Navigator>
  );
}

export function Navegador() {
  return (
    <NavigationContainer>
      <MyStack />
    </NavigationContainer>
  );
}

import { Button, Text, TextInput, View } from 'react-native';
import React, { useState } from 'react';
import { signInWithEmailAndPassword } from 'firebase/auth';
import { auth } from '../firebase/config';

export default function LoginScreen({ navigation }: any) {
  const [correo, setcorreo] = useState(' ');
  const [contrasenia, setcontrasenia] = useState(' ');

  function login() {
    signInWithEmailAndPassword(auth, correo, contrasenia)
      .then(() => {
        navigation.navigate('Drawer');
      })
      .catch((error) => {
        alert(error.message);
      });
  }

  return (
    <View>
      <Text>LoginScreen</Text>
      <TextInput placeholder='Ingresar correo' onChangeText={setcorreo} />
      <TextInput placeholder='Ingresar contraseña' onChangeText={setcontrasenia} />
      <Button title='login' onPress={login} />
      <Button title='ir a registro' onPress={() => navigation.navigate('Registro')} />
    </View>
  );
}

import { Button, Text, TextInput, View } from 'react-native';
import React, { useState } from 'react';
import { createUserWithEmailAndPassword } from 'firebase/auth';
import { auth, db } from '../firebase/config';
import { ref, set } from 'firebase/database';

export default function RegistroScreen({ navigation }: any) {
  const [correo, setcorreo] = useState(' ');
  const [nick, setnick] = useState(' ');
  const [edad, setedad] = useState(0);
  const [contrasenia, setcontrasenia] = useState(' ');

  function registro() {
    createUserWithEmailAndPassword(auth, correo, contrasenia)
      .then((userCredential) => {
        guardarUsuario(userCredential.user.uid);
        navigation.navigate('Login');
      })
      .catch((error) => {
        alert(error.message);
      });
  }

  function guardarUsuario(uid: string) {
    set(ref(db, 'usuarios/' + uid), {
      correo: correo,
      avatar: nick,
      edad: edad
    });
  }

  return (
    <View>
      <Text>RegistroScreen</Text>
      <TextInput placeholder='Ingresa correo' onChangeText={setcorreo} />
      <TextInput placeholder='Ingresa nick' onChangeText={setnick} />
      <TextInput placeholder='Ingresa edad' onChangeText={(texto) => setedad(+texto)} keyboardType='numeric' />
      <TextInput placeholder='Ingresa contrasenia' onChangeText={setcontrasenia} secureTextEntry />
      <Button title='registrar' onPress={registro} />
    </View>
  );
}

import { Button, Text, TextInput, View } from 'react-native';
import React, { useEffect, useState } from 'react';
import { ref, set } from 'firebase/database';
import { auth, db } from '../firebase/config';
import { onAuthStateChanged } from 'firebase/auth';

export default function GuardarScreen() {
  const [titulo, settitulo] = useState('');
  const [descripcion, setdescripcion] = useState('');
  const [fecha, setfecha] = useState('');
  const [id, setid] = useState('');

  function guardarNota() {
    set(ref(db, 'usuarios/' + id + '/notas/' + titulo), {
      titulo,
      descripcion,
      fecha
    });
    settitulo('');
    setdescripcion('');
    setfecha('');
  }

  function leerUID() {
    onAuthStateChanged(auth, (user) => {
      if (user) {
        setid(user.uid);
      }
    });
  }

  useEffect(() => {
    leerUID();
  }, []);

  return (
    <View>
      <Text>GuardarScreen</Text>
      <TextInput placeholder='Ingresa Titulo' onChangeText={settitulo} value={titulo} />
      <TextInput placeholder='Ingresa descripcion' onChangeText={setdescripcion} value={descripcion} />
      <TextInput placeholder='Ingresa fecha' onChangeText={setfecha} value={fecha} />
      <Button title='guardar' onPress={guardarNota} />
    </View>
  );
}

import { FlatList, Text, View, Button } from 'react-native'
import React, { useEffect, useState } from 'react'
import { auth, db } from '../firebase/config'
import { onAuthStateChanged } from 'firebase/auth'
import { ref, onValue, remove } from 'firebase/database'

export default function NotasScreen() {
  const [id, setid] = useState('')
  const [notas, setnotas] = useState([])

  // 🔹 Leer notas desde Firebase
  function leer() {
    const starCountRef = ref(db, 'usuarios/' + id + '/notas/')

    onValue(starCountRef, (snapshot) => {
      const data = snapshot.val()

      if (data) {
        let notasTemporales: any = Object.keys(data).map(ide => ({
          ide,
          ...data[ide]
        }))
        setnotas(notasTemporales)
      } else {
        setnotas([])
      }
    })
  }

  // 🔹 Obtener UID del usuario
  function leerUID() {
    onAuthStateChanged(auth, (user) => {
      if (user) {
        setid(user.uid)
      }
    })
  }

  // 🔹 ELIMINAR NOTA
  function eliminarNota(titulo: string) {
    remove(ref(db, 'usuarios/' + id + '/notas/' + titulo))
  }

  // Ejecutar correctamente
  useEffect(() => {
    leerUID()
  }, [])

  useEffect(() => {
    if (id) {
      leer()
    }
  }, [id])

  return (
    <View>
      <Text>NotasScreen</Text>

      <FlatList
        data={notas}
        keyExtractor={(item: any) => item.titulo}
        renderItem={({ item }: any) => (
          <View style={{ marginBottom: 10 }}>
            <Text>{item.titulo}</Text>
            <Text>{item.descripcion}</Text>
            <Text>{item.fecha}</Text>

            <Button 
              title="Eliminar" 
              onPress={() => eliminarNota(item.titulo)} 
            />
          </View>
        )}
      />
    </View>
  )
}

import { FlatList, Text, View } from 'react-native';
import React, { useEffect, useState } from 'react';
import Tarjeta from '../components/Tarjeta';

export default function ListaScreen() {
  const [peliculas, setpeliculas] = useState([]);
  const API_PELICULAS = 'https://jritsqmet.github.io/web-api/peliculas3.json';

  async function leerPeliculas() {
    const resp = await fetch(API_PELICULAS);
    const json = await resp.json();
    setpeliculas(json.peliculas);
  }

  useEffect(() => {
    leerPeliculas();
  }, []);

  return (
    <View>
      <Text>ListaScreen</Text>
      <FlatList data={peliculas} renderItem={({ item }: any) => <Tarjeta datos={item} />} />
    </View>
  );
}

import { Button, Text, View } from 'react-native';
import React, { useEffect, useState } from 'react';
import { onAuthStateChanged, signOut } from 'firebase/auth';
import { auth, db } from '../firebase/config';
import { onValue, ref } from 'firebase/database';

export default function InformacionScreen() {
  const [usuario, setusuario] = useState({ avatar: '', edad: 0 });

  function leerUsuario() {
    onAuthStateChanged(auth, (user) => {
      if (user) {
        getusuario(user.uid);
      }
    });
  }

  function getusuario(uid: string) {
    const starCountRef = ref(db, 'usuarios/' + uid);
    onValue(starCountRef, (snapshot) => {
      const data = snapshot.val();
      setusuario(data);
    });
  }

  function cerrarSesion() {
    signOut(auth);
  }

  useEffect(() => {
    leerUsuario();
  }, []);

  return (
    <View>
      <Text>InformacionScreen</Text>
      <Text>NOMBRE: {usuario.avatar}</Text>
      <Text>edad: {usuario.edad}</Text>
      <Button title='cerrar' onPress={cerrarSesion} />
    </View>
  );
}

